#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // allocate arrays sized by max possible node value (100000) + 1
        static int left[100001];
        static int right[100001];
        static int isChild[100001];
        // reset only needed part
        for (int i = 0; i <= 100000; ++i) { left[i]=right[i]=0; isChild[i]=0; }
        int maxNode = 0;
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') left[p] = c; else right[p] = c;
            isChild[c] = 1;
            if (p > maxNode) maxNode = p;
            if (c > maxNode) maxNode = c;
        }
        int root = 0;
        for (int i = 1; i <= maxNode; ++i) {
            if ((left[i] || right[i] || isChild[i]) && !isChild[i]) { root = i; break; }
        }
        // recursive postorder using explicit stack to avoid deep recursion in C
        // but N <= 15, recursion is fine
        void postorder(int node) {
            if (node == 0) return;
            postorder(left[node]);
            postorder(right[node]);
            printf("%d ", node);
        }
        postorder(root);
        printf("\n");
    }
    return 0;
}

