import java.io.*;
import java.util.*;

public class Main {
    static void postorder(int node, int[] left, int[] right, StringBuilder sb) {
        if (node == 0) return;
        postorder(left[node], left, right, sb);
        postorder(right[node], left, right, sb);
        sb.append(node).append(' ');
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int MAXV = 100000;
            int[] left = new int[MAXV+1];
            int[] right = new int[MAXV+1];
            boolean[] isChild = new boolean[MAXV+1];
            int maxNode = 0;
            for (int i = 0; i < N-1; ++i) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if (dir == 'L') left[p] = c; else right[p] = c;
                isChild[c] = true;
                maxNode = Math.max(maxNode, Math.max(p, c));
            }
            int root = 0;
            for (int i = 1; i <= maxNode; ++i) {
                if ((left[i] != 0 || right[i] != 0 || isChild[i]) && !isChild[i]) { root = i; break; }
            }
            StringBuilder sb = new StringBuilder();
            postorder(root, left, right, sb);
            out.append(sb.toString().trim()).append('\n');
        }
        System.out.print(out.toString());
    }
}

