import sys

def postorder(node, left, right, out):
    if node == 0:
        return
    postorder(left.get(node, 0), left, right, out)
    postorder(right.get(node, 0), left, right, out)
    out.append(str(node))

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        left = {}
        right = {}
        is_child = set()
        max_node = 0
        for __ in range(N-1):
            p = int(next(it)); c = int(next(it)); d = next(it)
            if d == 'L':
                left[p] = c
            else:
                right[p] = c
            is_child.add(c)
            max_node = max(max_node, p, c)
        # find root
        root = None
        for node in range(1, max_node+1):
            if (node in left or node in right or node in is_child) and node not in is_child:
                root = node
                break
        traversal = []
        postorder(root, left, right, traversal)
        out_lines.append(' '.join(traversal))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

